#include <iostream>

bool enable_reset_functionality = true;

void resetToZero(int& num);

int main() {
    int val1 = 5;
    std::cout << "Initial value 1: " << val1 << std::endl;
    enable_reset_functionality = true;
    resetToZero(val1);
    std::cout << "After resetToZero (enabled): " << val1 << std::endl;

    std::cout << "--------------------" << std::endl;

    int val2 = -10;
    enable_reset_functionality = false;
    std::cout << "Initial value 2: " << val2 << std::endl;
    resetToZero(val2);
    std::cout << "After resetToZero (disabled): " << val2 << std::endl;

    std::cout << "--------------------" << std::endl;

    int val3 = 100;
    enable_reset_functionality = true;
    std::cout << "Initial value 3: " << val3 << std::endl;
    resetToZero(val3);
    std::cout << "After resetToZero (re-enabled): " << val3 << std::endl;

    return 0;
}
